function createCapacitorFiles(projectName, platforms) {
  const appId = appIdFromName(projectName);
  const config = {
    appId,
    appName: projectName,
    webDir: 'dist',
  };

  if (platforms.includes('ios')) {
    config.ios = { path: 'native/mobile/ios' };
  }

  if (platforms.includes('android')) {
    config.android = { path: 'native/mobile/android' };
  }

  return [
    {
      filePath: 'capacitor.config.json',
      content: `${JSON.stringify(config, null, 2)}\n`,
    },
    {
      filePath: 'native/mobile/README.md',
      content: `# Mobile (Capacitor)\n\nEnabled platforms: ${platforms.filter((item) => MOBILE_PLATFORMS.includes(item)).join(', ')}\n\nCommands:\n\n\`\`\`bash\npnpm cap:sync\n\`\`\`\n`,
    },
  ];
}

function normalizeRustPackageName(projectName) {
  const base = (projectName || 'snative-app').replace(/[^a-z0-9_-]/gi, '-').toLowerCase();
  const cleaned = base.replace(/-+/g, '-').replace(/^[-_]+|[-_]+$/g, '');

  if (!cleaned) {
    return 'snative-app';
  }

  return /^[a-z]/.test(cleaned) ? cleaned : `app-${cleaned}`;
}

function rustLibNameFromPackageName(packageName) {
  const normalized = String(packageName || 'snative_app').replace(/-/g, '_');
  return /^[a-z_]/.test(normalized) ? normalized : `app_${normalized}`;
}

function createTauriCargoToml(projectName) {
  const rustPackageName = normalizeRustPackageName(projectName);
  const rustLibName = rustLibNameFromPackageName(rustPackageName);

  return `[package]
name = "${rustPackageName}"
version = "0.1.0"
description = "SNative desktop shell"
authors = ["SNative"]
edition = "2021"
rust-version = "1.77.2"

[lib]
name = "${rustLibName}"
crate-type = ["staticlib", "cdylib", "rlib"]

[build-dependencies]
tauri-build = { version = "2", features = [] }

[dependencies]
tauri = { version = "2", features = [] }
serde = { version = "1", features = ["derive"] }
serde_json = "1"
`;
}

function createTauriMainRs(projectName) {
  const rustPackageName = normalizeRustPackageName(projectName);
  const rustLibName = rustLibNameFromPackageName(rustPackageName);

  return `#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]

fn main() {
  ${rustLibName}::run();
}
`;
}

function createTauriLibRs() {
  return `#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
  tauri::Builder::default()
    .run(tauri::generate_context!())
    .expect("error while running tauri application");
}
`;
}

function createTauriFiles(projectName, platforms) {
  const appId = appIdFromName(projectName);

  return [
    {
      filePath: 'native/desktop/src-tauri/tauri.conf.json',
      content: `${JSON.stringify({
        $schema: 'https://schema.tauri.app/config/2',
        productName: projectName,
        identifier: appId,
        build: {
          frontendDist: '../../../dist',
          beforeBuildCommand: 'pnpm build',
          devUrl: 'http://localhost:5173',
          beforeDevCommand: 'pnpm dev',
        },
        app: {
          windows: [{ title: projectName, width: 1200, height: 760 }],
          security: { csp: null },
        },
      }, null, 2)}\n`,
    },
    {
      filePath: 'native/desktop/src-tauri/Cargo.toml',
      content: createTauriCargoToml(projectName),
    },
    {
      filePath: 'native/desktop/src-tauri/build.rs',
      content: 'fn main() {\n  tauri_build::build()\n}\n',
    },
    {
      filePath: 'native/desktop/src-tauri/src/main.rs',
      content: createTauriMainRs(projectName),
    },
    {
      filePath: 'native/desktop/src-tauri/src/lib.rs',
      content: createTauriLibRs(),
    },
    {
      filePath: 'native/desktop/src-tauri/capabilities/default.json',
      content: `${JSON.stringify({
        $schema: '../gen/schemas/desktop-schema.json',
        identifier: 'default',
        description: 'enables the default permissions',
        windows: ['main'],
        permissions: ['core:default'],
      }, null, 2)}\n`,
    },
    {
      filePath: 'native/desktop/src-tauri/.gitignore',
      content: '/target\n',
    },
    {
      filePath: 'native/desktop/README.md',
      content: `# Desktop (Tauri)\n\nEnabled platforms: ${platforms.filter((item) => DESKTOP_PLATFORMS.includes(item)).join(', ')}\n\nCommands:\n\n\`\`\`bash\npnpm desktop:dev\n\`\`\`\n`,
    },
  ];
}

export async function generateProject({ targetDir, config }) {
  const platforms = dedupe(config.platforms.includes('web') ? config.platforms : ['web', ...config.platforms]);
  const hasMobile = hasAny(platforms, MOBILE_PLATFORMS);
  const hasDesktop = hasAny(platforms, DESKTOP_PLATFORMS);

  await writeJson(path.join(targetDir, 'package.json'), createRootPackageJson(config.projectName, platforms, hasMobile, hasDesktop));
  await writeFileSafe(path.join(targetDir, '.gitignore'), 'node_modules\n.DS_Store\ndist\n.env\n');
  await writeJson(path.join(targetDir, 'snative.config.json'), {
    schemaVersion: 2,
    projectName: config.projectName,
    platforms,
    runtimes: {
      mobile: hasMobile ? 'capacitor' : null,
      desktop: hasDesktop ? 'tauri' : null,
    },
  });

  await writeFileSafe(path.join(targetDir, 'README.md'), createRootReadme(config.projectName, platforms, hasMobile, hasDesktop));
  await writeFileSafe(path.join(targetDir, '.env.example'), createEnvExample());
  await writeFileSafe(path.join(targetDir, 'GUIDE.es.md'), createGuideEs());
  await writeFileSafe(path.join(targetDir, 'GUIDE.en.md'), createGuideEn());

  await writeFileSafe(path.join(targetDir, 'app/index.html'), `<!doctype html>\n<html lang="en">\n  <head>\n    <meta charset="UTF-8" />\n    <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n    <title>${config.projectName}</title>\n  </head>\n  <body>\n    <div id="app"></div>\n    <script type="module" src="/main/main.js"></script>\n  </body>\n</html>\n`);

  await writeFileSafe(path.join(targetDir, 'vite.config.js'), `import { defineConfig } from 'vite';\nimport { svelte } from '@sveltejs/vite-plugin-svelte';\n\nexport default defineConfig({\n  root: 'app',\n  build: {\n    outDir: '../dist',\n    emptyOutDir: true,\n  },\n  plugins: [svelte()],\n});\n`);

  await writeFileSafe(path.join(targetDir, 'svelte.config.js'), 'export default {};\n');

  await writeFileSafe(path.join(targetDir, 'app/main/main.js'), `import './app.css';\nimport App from './App.svelte';\n\nnew App({\n  target: document.getElementById('app'),\n});\n`);

  await writeFileSafe(path.join(targetDir, 'app/main/app.css'), `html, body, #app {\n  margin: 0;\n  min-height: 100%;\n}\n\nbody {\n  font-family: system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, Arial, sans-serif;\n}\n`);

  await writeFileSafe(path.join(targetDir, 'app/main/App.svelte'), createAppSvelte());

  await writeFileSafe(path.join(targetDir, 'app/routes/config.js'), createRouterConfig());
  await writeFileSafe(path.join(targetDir, 'app/routes/goto.js'), createRouterGoto());
  await writeFileSafe(path.join(targetDir, 'app/routes/index.js'), createRouterIndex());
  await writeFileSafe(path.join(targetDir, 'app/routes/Router.svelte'), createRouterSvelte());

  await writeFileSafe(path.join(targetDir, 'app/modules/home/Home.svelte'), createHomeSvelte());
  await writeFileSafe(path.join(targetDir, 'app/modules/errors/NotFound.svelte'), createNotFoundSvelte());

  await writeFileSafe(path.join(targetDir, 'app/config/.gitkeep'), '');
  await writeFileSafe(path.join(targetDir, 'app/assets/.gitkeep'), '');
  await writeFileSafe(path.join(targetDir, 'app/models/.gitkeep'), '');
  await writeFileSafe(path.join(targetDir, 'app/services/.gitkeep'), '');
  await writeFileSafe(path.join(targetDir, 'app/stores/.gitkeep'), '');
  await writeFileSafe(path.join(targetDir, 'app/test/.gitkeep'), '');
  await writeFileSafe(path.join(targetDir, 'app/themes/.gitkeep'), '');
  await writeFileSafe(path.join(targetDir, 'app/ui/.gitkeep'), '');

  if (hasMobile) {
    const files = createCapacitorFiles(config.projectName, platforms);
    for (const file of files) {
      await writeFileSafe(path.join(targetDir, file.filePath), file.content);
    }
  }

  if (hasDesktop) {
    const files = createTauriFiles(config.projectName, platforms);
    for (const file of files) {
      await writeFileSafe(path.join(targetDir, file.filePath), file.content);
    }

    const iconBytes = Buffer.from(TAURI_DEFAULT_ICON_PNG_BASE64, 'base64');
    await writeBinaryFileSafe(path.join(targetDir, 'native/desktop/src-tauri/icons/icon.png'), iconBytes);
  }

  return {
    hasMobile,
    hasDesktop,
    normalizedConfig: {
      ...config,
      platforms,
    },
  };
}
